Code.Terraform:
```hcl
# ネットワーク分離が有効になっているSageMakerモデル
resource "aws_sagemaker_model" "<example_resource_name>" {
  name               = "<example_resource_name>"
  execution_role_arn = "<example_resource_arn>"

  primary_container {
    image = "<example_image>"
  }

  enable_network_isolation = true  # 重大: チェックに合格するためにネットワーク分離を有効にする
}
```
